class Solution:
    def smallestValue(self, n: int) -> int:
        def prime_factors_sum(n):
            sum_factors = 0
            i = 2
            while i * i <= n:
                while n % i == 0:
                    sum_factors += i
                    n //= i
                i += 1
            if n > 1:
                sum_factors += n
            return sum_factors

        seen = set()
        while n not in seen:
            seen.add(n)
            n = prime_factors_sum(n)
        return n
